Use ASP.NET Core's `WebApplicationFactory<T>` — it hosts your app in-memory with a `TestServer`, giving you a real `HttpClient` without opening a network port.

```csharp
// MyMcpServer.IntegrationTests.csproj
// Add refs: Microsoft.AspNetCore.Mvc.Testing, xunit

public class McpProtocolTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpProtocolTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list",
            @params = new { }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-process `TestServer`.
- **Full pipeline** — middleware, DI, routing all execute as in production.
- **SSE/Streamable HTTP** — for streaming endpoints, use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the response stream.
- **Mock dependencies** — override services via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`.

Make sure your `Program` class is accessible (add `[assembly: InternalsVisibleTo("YourTestProject")]` or use a `public partial class Program { }` marker).
